def canonicalize_newick(
    newick: str,
    *,
    outgroup_prefer=("0", "1"),
    collapse_unary=False,
    float_sig=10,
) -> str:
    t = EteTree(newick, format=1, quoted_node_names=True)

    if collapse_unary:
        changed = True
        while changed:
            changed = False
            for n in list(t.traverse("postorder")):
                if n.up is None:
                    continue
                if (not n.is_leaf()) and len(n.children) == 1:
                    ch = n.children[0]
                    ch.dist = float(ch.dist) + float(n.dist)
                    parent = n.up
                    n.detach()
                    parent.add_child(ch)
                    changed = True

    leaves = {lf.name: lf for lf in t.iter_leaves()}
    rooted = False
    for lbl in outgroup_prefer:
        if lbl in leaves:
            t.set_outgroup(leaves[lbl])
            rooted = True
            break
    if not rooted:
        t.set_outgroup(min(t.iter_leaves(), key=lambda x: int(x.name)))

    def rec(n):
        if n.is_leaf():
            lid = int(n.name)
            n.add_feature("_minleaf", lid)
            n.add_feature("_mask", 1 << lid)
            return

        for ch in n.children:
            rec(ch)

        n._minleaf = min(int(ch._minleaf) for ch in n.children) if n.children else 0
        m = 0
        for ch in n.children:
            m |= int(ch._mask)
        n._mask = int(m)

        n.children.sort(key=lambda c: (int(c._minleaf), int(c._mask)))

    rec(t)

    def fmt_len(x: float) -> str:
        return f"{float(x):.{float_sig}g}"

    def emit(n) -> str:
        if n.is_leaf():
            s = n.name
        else:
            s = "(" + ",".join(emit(ch) for ch in n.children) + ")"
        if n.up is None:
            return s
        return s + ":" + fmt_len(n.dist)

    return emit(t) + ";"


class TestTreeTokenization(unittest.TestCase):
    """Test that trees with the same topology produce identical tokenizations."""

    @classmethod
    def setUpClass(cls):
        cls.tokenizer = TreeFeatureTokenizer(3, 2, 256)
        cls.tokenization_one = cls.tokenizer([TREE_ONE])
        cls.tokenization_two = cls.tokenizer([TREE_TWO])
        cls.canonical_one = canonicalize_newick(TREE_ONE)
        cls.canonical_two = canonicalize_newick(TREE_TWO)

    def test_same_topology(self):
        """Canonicalized trees should have zero Robinson-Foulds distance."""
        rf = calculate_norm_rf(self.canonical_one, self.canonical_two)
        self.assertEqual(
            rf,
            0,
            "Canonicalized trees have non-zero RF distance — topology mismatch",
        )

    def test_tokenization_length_match(self):
        """Tokenizations of same-topology trees must have the same sequence length."""
        self.assertEqual(
            self.tokenization_one[0].shape[1],
            self.tokenization_two[0].shape[1],
            "Tokenized tree lengths differ "
            f"({self.tokenization_one[0].shape[1]} vs {self.tokenization_two[0].shape[1]})",
        )

    def test_tokenization_values_match(self):
        """Tokenization tensors for same-topology trees must be element-wise equal."""
        self.assertTrue(
            (self.tokenization_one[0] == self.tokenization_two[0]).all().item(),
            "Tokenized tree tensors are not identical",
        )


if __name__ == "__main__":
    unittest.main()
